def validate(args, output):
    s = args[0]
    if not isinstance(output, str):
        return False
    def has_dup(length):
        if length == 0:
            return True
        seen = set()
        for i in range(len(s) - length + 1):
            sub = s[i:i + length]
            if sub in seen:
                return True
            seen.add(sub)
        return False
    # find the true maximum duplicate length
    lo, hi = 0, len(s) - 1
    best = 0
    while lo <= hi:
        mid = (lo + hi) // 2
        if has_dup(mid):
            best = mid
            lo = mid + 1
        else:
            hi = mid - 1
    if len(output) != best:
        return False
    if best == 0:
        return output == ''
    # output must actually be a substring of s that occurs at least twice
    count = 0
    idx = s.find(output)
    while idx != -1:
        count += 1
        if count >= 2:
            return True
        idx = s.find(output, idx + 1)
    return False

