function validate(args, output) {
    const s = args[0];
    if (typeof output !== 'string') return false;
    const hasDup = (length) => {
        if (length === 0) return true;
        const seen = new Set();
        for (let i = 0; i + length <= s.length; i++) {
            const sub = s.substring(i, i + length);
            if (seen.has(sub)) return true;
            seen.add(sub);
        }
        return false;
    };
    let lo = 0, hi = s.length - 1, best = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (hasDup(mid)) { best = mid; lo = mid + 1; }
        else hi = mid - 1;
    }
    if (output.length !== best) return false;
    if (best === 0) return output === '';
    let count = 0;
    let idx = s.indexOf(output);
    while (idx !== -1) {
        count++;
        if (count >= 2) return true;
        idx = s.indexOf(output, idx + 1);
    }
    return false;
}

