class Solution:
    def longestDupSubstring(self, s):
        n = len(s)
        def has(length):
            seen = {}
            for i in range(n - length + 1):
                sub = s[i:i + length]
                if sub in seen:
                    return True
                seen[sub] = i
            return False
        lo, hi, best_len = 0, n - 1, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if has(mid):
                best_len = mid
                lo = mid + 1
            else:
                hi = mid - 1
        if best_len == 0:
            return ''
        best = None
        seen = set()
        for i in range(n - best_len + 1):
            sub = s[i:i + best_len]
            if sub in seen:
                if best is None or sub < best:
                    best = sub
            else:
                seen.add(sub)
        return best

