class Solution:
    def longestDupSubstring(self, s):
        n = len(s)
        nums = [ord(c) - 97 for c in s]
        MOD = (1 << 61) - 1
        BASE = 131
        def search(length):
            if length == 0:
                return 0
            h = 0
            for i in range(length):
                h = (h * BASE + nums[i]) % MOD
            power = pow(BASE, length, MOD)
            seen = {h: [0]}
            for i in range(1, n - length + 1):
                h = (h * BASE - nums[i - 1] * power + nums[i + length - 1]) % MOD
                if h in seen:
                    cur = s[i:i + length]
                    for j in seen[h]:
                        if s[j:j + length] == cur:
                            return i
                    seen[h].append(i)
                else:
                    seen[h] = [i]
            return -1
        lo, hi, best_len = 0, n - 1, 0
        while lo <= hi:
            mid = (lo + hi) // 2
            if search(mid) != -1:
                best_len = mid
                lo = mid + 1
            else:
                hi = mid - 1
        if best_len == 0:
            return ''
        best = None
        seen = set()
        for i in range(n - best_len + 1):
            sub = s[i:i + best_len]
            if sub in seen:
                if best is None or sub < best:
                    best = sub
            else:
                seen.add(sub)
        return best

