var longestDupSubstring = function(s) {
    const n = s.length;
    const hasDup = (length) => {
        if (length === 0) return true;
        const seen = new Set();
        for (let i = 0; i + length <= n; i++) {
            const sub = s.substring(i, i + length);
            if (seen.has(sub)) return true;
            seen.add(sub);
        }
        return false;
    };
    let lo = 0, hi = n - 1, bestLen = 0;
    while (lo <= hi) {
        const mid = (lo + hi) >> 1;
        if (hasDup(mid)) { bestLen = mid; lo = mid + 1; }
        else hi = mid - 1;
    }
    if (bestLen === 0) return '';
    let best = null;
    const seen = new Set();
    for (let i = 0; i + bestLen <= n; i++) {
        const sub = s.substring(i, i + bestLen);
        if (seen.has(sub)) {
            if (best === null || sub < best) best = sub;
        } else {
            seen.add(sub);
        }
    }
    return best;
};
